export function emitJson(event) {
    process.stdout.write(`${JSON.stringify(event)}\n`);
}
/**
 * One-line description of a command that stays alive waiting on a Studio
 * interaction, with invocation guidance for agents. Surfaced in two places
 * so an agent learns the contract BEFORE it hangs a foreground call:
 *
 *   1. usage output (via parseArgs' `usageNote`), so a no-args probe like
 *      `node startDataset.js` teaches the contract up front
 *   2. a stderr banner printed at command startup (printBlockingNotice)
 *
 * Skill text alone cannot prevent foreground hangs: agents call these CLIs
 * cold, before any skill is loaded. The commands must describe themselves.
 */
export function blockingNote(until) {
    return (`BLOCKING: this command does not exit until ${until}. ` +
        "Agents: run it in the background and read its stdout incrementally. " +
        "A foreground call hangs the conversation until the process exits.");
}
/** Print the blocking contract to stderr (stdout stays a JSONL stream). */
export function printBlockingNotice(until) {
    console.error(blockingNote(until));
}
